     1→/*
     2→ * lrint() test harness — prints (input_hex, output_long) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly lrint  (test_lrint_opt.elf)
     6→ *   2. Linked with toolchain's default lrint        (test_lrint_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <limits.h>
    14→#include <float.h>
    15→
    16→#ifdef EN_PERF
    17→#define PF_COUNTER
    18→#include "nds_pfcounter.h"
    19→#endif
    20→
    21→static inline uint64_t d2u(double d)
    22→{
    23→    union { double d; uint64_t u; } x;
    24→    x.d = d;
    25→    return x.u;
    26→}
    27→
    28→static inline double u2d(uint64_t u)
    29→{
    30→    union { double d; uint64_t u; } x;
    31→    x.u = u;
    32→    return x.d;
    33→}
    34→
    35→#ifdef EN_PERF
    36→static volatile long g_acc;
    37→
    38→static void emit(double x)
    39→{
    40→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    41→    g_acc += lrint(vx);
    42→}
    43→
    44→static void emit_u(uint64_t bits)
    45→{
    46→    emit(u2d(bits));
    47→}
    48→#else
    49→static void emit(double x)
    50→{
    51→    long r = lrint(x);
    52→    printf("%016llx %016lx\n", (unsigned long long)d2u(x), (unsigned long)r);
    53→}
    54→
    55→static void emit_u(uint64_t bits)
    56→{
    57→    emit(u2d(bits));
    58→}
    59→#endif
    60→
    61→/* ------------------------------------------------------------------ */
    62→/* test_representative_100: 100 representative inputs                  */
    63→/* ------------------------------------------------------------------ */
    64→
    65→static void test_representative_100(void)
    66→{
    67→    /* --- Section 1: Special IEEE 754 values (7) --- */
    68→    emit(0.0);
    69→    emit(-0.0);
    70→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    71→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    72→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    73→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    74→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    75→
    76→    /* --- Section 2: Subnormal values (6) --- */
    77→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    78→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    79→    emit_u(0x0008000000000000ULL);  /* mid subnormal */
    80→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    81→    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    82→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    83→
    84→    /* --- Section 3: Normal boundary values (5) --- */
    85→    emit(DBL_MIN);                  /* 2^-1022, smallest normal positive */
    86→    emit(-DBL_MIN);
    87→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    88→    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX */
    89→    emit_u(0xffefffffffffffffULL);  /* -DBL_MAX */
    90→
    91→    /* --- Section 4: Near-zero: tiny fractions that round to 0 (8) --- */
    92→    emit(1.0e-200);
    93→    emit(-1.0e-200);
    94→    emit(1.0e-10);
    95→    emit(-1.0e-10);
    96→    emit(0.4999999999999999);       /* just below 0.5 — rounds to 0 */
    97→    emit(-0.4999999999999999);
    98→    emit_u(0x3fdffffffffffffeULL);  /* 0.5 - 1 ULP: just below half */
    99→    emit_u(0xbfdffffffffffffeULL);  /* -0.5 + 1 ULP: just above -half */
   100→
   101→    /* --- Section 5: Half-way (banker's rounding) values (12) --- */
   102→    emit(0.5);
   103→    emit(-0.5);
   104→    emit(1.5);
   105→    emit(-1.5);
   106→    emit(2.5);
   107→    emit(-2.5);
   108→    emit(3.5);
   109→    emit(-3.5);
   110→    emit(4.5);
   111→    emit(-4.5);
   112→    emit(5.5);
   113→    emit(-5.5);
   114→
   115→    /* --- Section 6: ULP neighbors of 0.5 and 1.5 boundaries (6) --- */
   116→    emit_u(0x3fe0000000000001ULL);  /* 0.5 + 1 ULP */
   117→    emit_u(0xbfe0000000000001ULL);  /* -0.5 - 1 ULP */
   118→    emit_u(0x3ff7ffffffffffffULL);  /* 1.5 - 1 ULP */
   119→    emit_u(0x3ff8000000000001ULL);  /* 1.5 + 1 ULP */
   120→    emit_u(0xbff7ffffffffffffULL);  /* -1.5 + 1 ULP */
   121→    emit_u(0xbff8000000000001ULL);  /* -1.5 - 1 ULP */
   122→
   123→    /* --- Section 7: Non-half fractional parts (14) --- */
   124→    emit(0.1);
   125→    emit(0.2);
   126→    emit(0.3);
   127→    emit(0.6);
   128→    emit(0.7);
   129→    emit(0.9);
   130→    emit(-0.1);
   131→    emit(-0.2);
   132→    emit(-0.3);
   133→    emit(-0.6);
   134→    emit(-0.7);
   135→    emit(-0.9);
   136→    emit(1.1);
   137→    emit(-1.1);
   138→
   139→    /* --- Section 8: Small positive integers (8) --- */
   140→    emit(1.0);
   141→    emit(2.0);
   142→    emit(3.0);
   143→    emit(4.0);
   144→    emit(5.0);
   145→    emit(10.0);
   146→    emit(100.0);
   147→    emit(1000.0);
   148→
   149→    /* --- Section 9: Powers of 2 at and near mantissa precision (8) --- */
   150→    emit_u(0x4330000000000000ULL);  /* 2^52: last integer where .5 matters */
   151→    emit_u(0x4340000000000000ULL);  /* 2^53: all integers exact, no frac */
   152→    emit_u(0x4350000000000000ULL);  /* 2^54 */
   153→    emit_u(0x432fffffffffffffULL);  /* just below 2^52 */
   154→    emit_u(0x433fffffffffffffULL);  /* just below 2^53 */
   155→    emit_u(0xc330000000000000ULL);  /* -2^52 */
   156→    emit_u(0xc340000000000000ULL);  /* -2^53 */
   157→    emit_u(0xc32fffffffffffffULL);  /* just above -2^52 */
   158→
   159→    /* --- Section 10: Large values in representable long range (8) --- */
   160→    emit(1.0e6);
   161→    emit(-1.0e6);
   162→    emit(1.0e9);
   163→    emit(-1.0e9);
   164→    emit(1.5e9);
   165→    emit(-1.5e9);
   166→    emit(1.0e15);
   167→    emit(-1.0e15);
   168→
   169→    /* --- Section 11: LONG_MAX / LONG_MIN boundary (10) --- */
   170→    emit((double)(LONG_MAX - 2));
   171→    emit((double)(LONG_MAX - 1));
   172→    emit((double)LONG_MAX);
   173→    emit((double)LONG_MIN);
   174→    emit((double)(LONG_MIN + 1));
   175→    emit((double)(LONG_MIN + 2));
   176→    emit(1.0e18);                   /* within long range on 64-bit */
   177→    emit(-1.0e18);
   178→    emit(1.0e19);                   /* overflow: beyond LONG_MAX on 64-bit */
   179→    emit(-1.0e19);
   180→
   181→    /* --- Section 12: Near-integer with fractional ULP neighbors (8) --- */
   182→    emit_u(0x3feffffffffffffeULL);  /* just below 1.0 - 0.5 = 0.5 */
   183→    emit_u(0x3ff0000000000001ULL);  /* 1.0 + 1 ULP */
   184→    emit_u(0x4000000000000001ULL);  /* 2.0 + 1 ULP */
   185→    emit_u(0x400fffffffffffffULL);  /* 3.0 - 1 ULP */
   186→    emit_u(0xbff0000000000001ULL);  /* -1.0 - 1 ULP */
   187→    emit_u(0xc000000000000001ULL);  /* -2.0 - 1 ULP */
   188→    emit_u(0xc00fffffffffffffULL);  /* -3.0 + 1 ULP */
   189→    emit_u(0x4014000000000000ULL);  /* 5.0 exact */
   190→}
   191→
   192→/* ------------------------------------------------------------------ */
   193→
   194→/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
   195→#ifndef EN_PERF
   196→static void test_sweep(void)
   197→{
   198→    double hi = 10.0;
   199→    int nsteps = 100;
   200→    double step = hi / (double)nsteps;
   201→
   202→    /* [0, 10] */
   203→    for (int i = 0; i <= nsteps; i++)
   204→        emit((double)i * step);
   205→
   206→    /* [-10, 0] */
   207→    for (int i = 0; i <= nsteps; i++)
   208→        emit(-hi + (double)i * step);
   209→}
   210→
   211→/* 8. Sample [0, 10] every ~0.05 (200 points) */
   212→static void test_exhaustive_small(void)
   213→{
   214→    double hi = 10.0;
   215→    int nsteps = 200;
   216→    double step = hi / (double)nsteps;
   217→
   218→    for (int i = 0; i <= nsteps; i++)
   219→        emit((double)i * step);
   220→}
   221→#endif
   222→
   223→/* ------------------------------------------------------------------ */
   224→
   225→int main(void)
   226→{
   227→#ifdef EN_PERF
   228→    startPFM;
   229→    test_representative_100();
   230→    stopPFM;
   231→    readResult();
   232→    printf("perf g_acc: %016lx\n", (unsigned long)g_acc);
   233→#else
   234→    test_representative_100();
   235→    test_sweep();
   236→    test_exhaustive_small();
   237→#endif
   238→    return 0;
   239→}
